import torchvision.models as models

class VGGPerceptualLoss(nn.Module):
    def __init__(self, layers=('relu_3_3', 'relu_4_3')):
        super().__init__()
        vgg = models.vgg19(weights=models.VGG19_Weights.IMAGENET1K_V1)
        # Freeze VGG — we use it as a fixed feature extractor
        for p in vgg.parameters():
            p.requires_grad_(False)

        # Build feature extractor up to each target layer
        layer_map = {
            'relu_1_2': 4, 'relu_2_2': 9,
            'relu_3_3': 18, 'relu_4_3': 27, 'relu_5_3': 36
        }
        end_idx = max(layer_map[l] for l in layers) + 1
        self.features = vgg.features[:end_idx]
        self.extract_at = {layer_map[l]: l for l in layers}

    def forward(self, fake, real):
        # Normalize to ImageNet mean/std
        mean = torch.tensor([0.485, 0.456, 0.406], device=fake.device).view(1, 3, 1, 1)
        std  = torch.tensor([0.229, 0.224, 0.225], device=fake.device).view(1, 3, 1, 1)
        fake_n = (fake * 0.5 + 0.5 - mean) / std  # [-1,1] → normalized
        real_n = (real * 0.5 + 0.5 - mean) / std

        loss = 0.0
        x_f, x_r = fake_n, real_n
        for i, layer in enumerate(self.features):
            x_f = layer(x_f)
            x_r = layer(x_r)
            if i in self.extract_at:
                loss += nn.functional.l1_loss(x_f, x_r.detach())
        return loss
